<?php require_once __DIR__.'/../includes/functions.php'; require_once __DIR__.'/../includes/db.php'; require_admin(); $pdo=db(); if($_SERVER['REQUEST_METHOD']==='POST'&&verify_csrf($_POST['csrf_token']??null)){ if(($_POST['action']??'')==='delete'){ $pdo->prepare('DELETE FROM social_links WHERE id=?')->execute([(int)$_POST['id']]); } else { $data=[post_value('platform'),post_value('url'),post_value('icon_class'),post_value('status')==='inactive'?'inactive':'active',(int)post_value('sort_order')]; if(!empty($_POST['id'])){ $data[]=(int)$_POST['id']; $pdo->prepare('UPDATE social_links SET platform=?,url=?,icon_class=?,status=?,sort_order=? WHERE id=?')->execute($data); } else { $pdo->prepare('INSERT INTO social_links (platform,url,icon_class,status,sort_order) VALUES (?,?,?,?,?)')->execute($data); } } redirect('social.php'); } include 'partials/header.php'; include 'partials/sidebar.php'; $rows=$pdo->query('SELECT * FROM social_links ORDER BY sort_order,id')->fetchAll(); ?><h2 class="mb-4 text-3xl font-black">Manage Social Links</h2><form method="post" class="mb-6 grid gap-3 rounded-2xl bg-white p-5 shadow md:grid-cols-2"><input type="hidden" name="csrf_token" value="<?=e(csrf_token())?>"><input name="platform" required class="rounded border p-3" placeholder="Platform"><input name="url" required class="rounded border p-3" placeholder="URL"><input name="icon_class" required class="rounded border p-3" placeholder="Font Awesome class"><input type="number" name="sort_order" value="0" class="rounded border p-3"><select name="status" class="rounded border p-3"><option value="active">active</option><option value="inactive">inactive</option></select><button class="rounded bg-slate-950 px-5 py-3 font-bold text-white">Add Social Link</button></form><div class="grid gap-4"><?php foreach($rows as $r):?><form method="post" class="grid gap-2 rounded-2xl bg-white p-4 shadow md:grid-cols-6"><input type="hidden" name="csrf_token" value="<?=e(csrf_token())?>"><input type="hidden" name="id" value="<?=e($r['id'])?>"><input name="platform" value="<?=e($r['platform'])?>" class="rounded border p-2"><input name="url" value="<?=e($r['url'])?>" class="rounded border p-2 md:col-span-2"><input name="icon_class" value="<?=e($r['icon_class'])?>" class="rounded border p-2"><input type="number" name="sort_order" value="<?=e($r['sort_order'])?>" class="rounded border p-2"><select name="status" class="rounded border p-2"><option <?=$r['status']==='active'?'selected':''?>>active</option><option <?=$r['status']==='inactive'?'selected':''?>>inactive</option></select><button class="rounded bg-blue-950 px-4 py-2 font-bold text-white">Update</button><button name="action" value="delete" onclick="return confirm('Delete this social link?')" class="rounded bg-red-700 px-4 py-2 font-bold text-white">Remove</button></form><?php endforeach;?></div><?php include 'partials/footer.php'; ?>
